# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;
using UnityEngine.UI;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int maxHealth = 100;
    public int currency = 0;
    public int attackPower = 10;
    public int defense = 0;

    public void TakeDamage(int incomingDamage)
    {
        int finalDamage = Mathf.Max(1, incomingDamage - defense);
        health = Mathf.Max(0, health - finalDamage);
    }

    public void Heal(int amount)
    {
        health = Mathf.Min(maxHealth, health + amount);
    }

    public bool CanAfford(int cost)
    {
        return currency >= cost;
    }

    public bool SpendCurrency(int cost)
    {
        if (!CanAfford(cost))
            return false;

        currency -= cost;
        return true;
    }

    public void AddCurrency(int amount)
    {
        currency = Mathf.Max(0, currency + amount);
    }
}

public class ShopItem : MonoBehaviour
{
    public string itemName;
    public int basePrice = 100;
    public int priceMultiplier = 2;
    public int baseDamageBonus = 5;
    public int baseHealthBonus = 0;
    public int baseDefenseBonus = 0;

    public int CalculatePrice(int currentPurchaseCount)
    {
        return basePrice + (currentPurchaseCount * priceMultiplier * basePrice);
    }

    public int CalculateDamageBonus(int upgradeLevel)
    {
        return baseDamageBonus + upgradeLevel;
    }

    public bool Purchase(PlayerStats player, int currentPurchaseCount, int upgradeLevel)
    {
        int price = CalculatePrice(currentPurchaseCount);
        if (!player.SpendCurrency(price))
            return false;

        player.attackPower += CalculateDamageBonus(upgradeLevel);
        player.maxHealth += baseHealthBonus;
        player.health += baseHealthBonus;
        player.defense += baseDefenseBonus;
        return true;
    }
}

public class ShopUI : MonoBehaviour
{
    public PlayerStats player;
    public ShopItem item;
    public Text currencyText;
    public Text healthText;
    public Text attackText;
    public Text priceText;

    public int currentPurchaseCount = 0;
    public int upgradeLevel = 0;

    void Start()
    {
        UpdateUI();
    }

    void Update()
    {
        UpdateUI();
    }

    public void BuyItem()
    {
        if (player == null || item == null)
            return;

        if (item.Purchase(player, currentPurchaseCount, upgradeLevel))
        {
            currentPurchaseCount++;
            upgradeLevel++;
        }

        UpdateUI();
    }

    private void UpdateUI()
    {
        if (player == null)
            return;

        if (currencyText != null)
            currencyText.text = "Currency: " + player.currency;

        if (healthText != null)
            healthText.text = "Health: " + player.health + "/" + player.maxHealth;

        if (attackText != null)
            attackText.text = "Attack: " + player.attackPower;

        if (priceText != null && item != null)
            priceText.text = "Price: " + item.CalculatePrice(currentPurchaseCount);
    }
}

public class DamageSystem : MonoBehaviour
{
    public PlayerStats player;
    public int enemyAttack = 20;

    public void ApplyEnemyDamage()
    {
        if (player != null)
            player.TakeDamage(enemyAttack);
    }

    public int CalculateClientSideDamage(int baseDamage, int bonusDamage, float damageMultiplier)
    {
        return Mathf.Max(1, Mathf.RoundToInt((baseDamage + bonusDamage) * damageMultiplier));
    }
}

public class InAppPurchaseReward : MonoBehaviour
{
    public PlayerStats player;
    public int currencyReward = 500;
    public int healthReward = 50;

    public void GrantReward()
    {
        if (player == null)
            return;

        player.AddCurrency(currencyReward);
        player.Heal(healthReward);
    }
}